import{_ as t,o,c as d,ag as r}from"./chunks/framework.CAXxHpAX.js";const p=JSON.parse('{"title":"V5.2 contracts release — keccak-on-chain amendment","description":"","frontmatter":{},"headers":[],"relativePath":"reference/release-notes/v0.5.2-contracts.md","filePath":"release-notes/v0.5.2-contracts.md","lastUpdated":1777988338000}'),a={name:"reference/release-notes/v0.5.2-contracts.md"};function s(c,e,i,n,l,h){return o(),d("div",null,[...e[0]||(e[0]=[r(`<h1 id="v5-2-contracts-release-—-keccak-on-chain-amendment" tabindex="-1">V5.2 contracts release — keccak-on-chain amendment <a class="header-anchor" href="#v5-2-contracts-release-—-keccak-on-chain-amendment" aria-label="Permalink to &quot;V5.2 contracts release — keccak-on-chain amendment&quot;">​</a></h1><p><strong>Renamed in v0.6.0</strong> — content reflects v0.5.x state; subsequent versions use zkqes nomenclature.</p><p><strong>Package:</strong> <code>@qkb/contracts</code>, <code>@qkb/contracts-sdk</code>, <code>@qkb/sdk</code><strong>Version:</strong> <code>0.5.1-pre</code> → <code>0.5.2-pre</code><strong>Branch:</strong> <code>feat/v5_2arch-contracts</code> (commits <code>024b62b..0118a93</code>) <strong>Spec:</strong> <code>docs/superpowers/specs/2026-05-01-keccak-on-chain-amendment.md</code> (circuits-eng v0.4 — folds contracts-eng&#39;s two substantive review findings, locked at <code>8f5277f</code> on <code>feat/v5_2arch-circuits</code>; merges to <code>main</code> with the V5.2 release) <strong>Contract review:</strong> <code>docs/superpowers/specs/2026-05-01-keccak-on-chain-contract-review.md</code> (PASS-WITH-NOTES, locked at <code>dc16330</code> + <code>94032a1</code> retraction footer)</p><p>V5.2 is a focused <strong>cross-chain portability + circuit-size</strong> amendment. The wallet-pubkey → msg.sender keccak gate moves from V5.1&#39;s in-circuit <code>Secp256k1AddressDerive</code> (~145K constraints) to a one-line on-chain reconstruction — <strong>no security loss, ~9K gas added at the contract layer, pot22 ceremony power sufficient</strong>.</p><h2 id="tl-dr-for-downstream-consumers" tabindex="-1">TL;DR for downstream consumers <a class="header-anchor" href="#tl-dr-for-downstream-consumers" aria-label="Permalink to &quot;TL;DR for downstream consumers&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Consumer surface</th><th>Breaking change?</th><th>Action required</th></tr></thead><tbody><tr><td><code>IQKBRegistry</code> view ABI (isVerified / nullifierOf / trustedListRoot)</td><td><strong>No</strong> — selectors byte-identical to V5/V5.1</td><td>None. Existing SDK readers + <code>IdentityEscrowNFT.isVerified()</code> consumers work unchanged against the new registry.</td></tr><tr><td><code>register(...)</code> / <code>rotateWallet(...)</code> write ABI</td><td><strong>Yes</strong> — function selectors changed (proof + public-signal tuple shape changed)</td><td>Re-bind to <code>qkbRegistryV5_2Abi</code> from <code>@qkb/sdk</code> (or <code>@qkb/contracts-sdk</code>).</td></tr><tr><td>Witness builder / circuit</td><td><strong>Yes</strong> — circuit emits 22 public signals (was 19); msg.sender no longer in-circuit</td><td>Use <code>buildWitnessV5_2</code> from <code>@qkb/sdk</code> (web-eng A7.3).</td></tr><tr><td>Constructor signature for deployer-tooling</td><td><strong>No</strong> — <code>(IGroth16Verifier*, address admin, bytes32 trustRoot, bytes32 policyRoot)</code> is parity-equivalent to V5.1</td><td>None. <code>DeployV5_2.s.sol</code> mirrors <code>DeployV5.s.sol</code> verbatim minus name swaps.</td></tr><tr><td>Storage layout (for off-chain indexers reading via <code>eth_getStorageAt</code>)</td><td><strong>No</strong> — slots 0..6 byte-identical to V5.1</td><td>None. Verified via <code>forge inspect QKBRegistryV5_2 storageLayout</code> against V5.1.</td></tr><tr><td>Contract address on Sepolia / mainnet</td><td><strong>Yes</strong> — fresh deploy (registry is non-upgradeable)</td><td>Update <code>fixtures/contracts/sepolia.json</code> after the V5.2 Sepolia deploy lands. Holders re-register from V5.1 via the existing fresh-QES flow; no upgrade path.</td></tr></tbody></table><h2 id="why-v5-2" tabindex="-1">Why V5.2 <a class="header-anchor" href="#why-v5-2" aria-label="Permalink to &quot;Why V5.2&quot;">​</a></h2><p><strong>Cross-chain portability.</strong> V5.1&#39;s <code>Secp256k1AddressDerive</code> baked an EVM-specific keccak gate (over the 64-byte uncompressed wallet pubkey) directly into the BN254 Groth16 circuit. The same circuit could not target a non-EVM-keccak chain — even if that chain has a BN254 pairing precompile and a P-256 ECDSA precompile (the other two V5 prerequisites). Moving keccak to the contract layer makes the <strong>circuit + zkey portable</strong> across BN254-Groth16 chains; the EVM-specific bind becomes one host-native op the new chain implements anyway.</p><p>(Caveat: the OTHER V5 host-portability gates — P-256 ECDSA precompile via RIP-7212 / EIP-7951, EVM-style <code>address = keccak(pk)[12:32]</code> caller-auth model — still apply. Non-EVM caller-auth models (Solana ed25519, Cosmos bech32, Move) need a per-chain auth-shim outside V5.2 scope. See contract review §&quot;Cost estimate&quot; for the full host-portability matrix.)</p><p><strong>Smaller circuit, simpler ceremony.</strong> V5.2 sheds <strong>−145,867 constraints</strong> (3,876,304 vs V5.1&#39;s 4,022,171). The savings push the constraint count comfortably under pot22&#39;s 4,194,304 limit (<strong>7.6% headroom</strong>), so the V5.2 multi-contributor ceremony can use a <strong>pot22 (4.19M)</strong> powers-of-tau instead of V5.1&#39;s pot23 (8.39M). Smaller pot ⇒ smaller witness ⇒ smaller proving key ⇒ less bandwidth + storage in the contributor flow.</p><h2 id="abi-changes" tabindex="-1">ABI changes <a class="header-anchor" href="#abi-changes" aria-label="Permalink to &quot;ABI changes&quot;">​</a></h2><h3 id="function-selectors" tabindex="-1">Function selectors <a class="header-anchor" href="#function-selectors" aria-label="Permalink to &quot;Function selectors&quot;">​</a></h3><p>Verified via <code>forge inspect QKBRegistryV5{,_2} methodIdentifiers</code>.</p><table tabindex="0"><thead><tr><th>Function</th><th>V5.1 selector</th><th>V5.2 selector</th><th>Notes</th></tr></thead><tbody><tr><td><code>register(...)</code></td><td><code>0x8843e757</code></td><td><strong><code>0x9ab660c7</code></strong></td><td>Public-signal tuple grew 19 → 22 fields ⇒ selector changed.</td></tr><tr><td><code>rotateWallet(...)</code></td><td><code>0x07d19c50</code></td><td><strong><code>0x9849ff37</code></strong></td><td>Same tuple-shape change ⇒ selector changed. (Rotation flow itself unchanged — bindingPk limbs are present in the proof but not consulted at gate time; the rotation auth ECDSA sig is the load-bearing primitive.)</td></tr><tr><td><code>isVerified(address)</code></td><td><code>0xb9209e33</code></td><td><code>0xb9209e33</code></td><td>Unchanged.</td></tr><tr><td><code>nullifierOf(address)</code></td><td><code>0x61e0a22e</code></td><td><code>0x61e0a22e</code></td><td>Unchanged.</td></tr><tr><td><code>trustedListRoot()</code></td><td><code>0x4b7f352e</code></td><td><code>0x4b7f352e</code></td><td>Unchanged.</td></tr><tr><td><code>policyRoot()</code></td><td><code>0xe98cdb8c</code></td><td><code>0xe98cdb8c</code></td><td>Unchanged.</td></tr><tr><td><code>identityCommitments(bytes32)</code></td><td><code>0x4d0d48b8</code></td><td><code>0x4d0d48b8</code></td><td>Unchanged.</td></tr><tr><td><code>identityWallets(bytes32)</code></td><td><code>0x8afb1b91</code></td><td><code>0x8afb1b91</code></td><td>Unchanged.</td></tr><tr><td><code>usedCtx(bytes32, bytes32)</code></td><td><code>0x3af1740b</code></td><td><code>0x3af1740b</code></td><td>Unchanged.</td></tr><tr><td><code>setTrustedListRoot</code>, <code>setPolicyRoot</code>, <code>transferAdmin</code></td><td>(admin)</td><td>(admin, identical selectors)</td><td>Unchanged.</td></tr><tr><td><code>poseidonT3()</code>, <code>poseidonT7()</code>, <code>groth16Verifier()</code>, <code>admin()</code></td><td>(getters)</td><td>(getters, identical selectors)</td><td>Unchanged.</td></tr></tbody></table><p><strong>Implication for SDK consumers:</strong> view-only readers + <code>IdentityEscrowNFT.isVerified()</code> consumers work against V5.2 with <strong>zero ABI binding changes</strong>. Only callers that <em>write</em> (i.e., that build register / rotateWallet calldata) need the new ABI.</p><h3 id="public-signal-layout" tabindex="-1">Public-signal layout <a class="header-anchor" href="#public-signal-layout" aria-label="Permalink to &quot;Public-signal layout&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Slot</th><th>V5.1</th><th>V5.2</th><th>Notes</th></tr></thead><tbody><tr><td>0</td><td><code>msgSender</code></td><td><code>timestamp</code></td><td>V5.1 slot 0 dropped. Wallet bind moves from circuit-emitted slot to on-chain keccak-derive of slots 18..21.</td></tr><tr><td>1</td><td><code>timestamp</code></td><td><code>nullifier</code></td><td>V5.1 slots 1..18 shift down by 1.</td></tr><tr><td>2..16</td><td>(V5.1 slot N)</td><td>(V5.1 slot N − 1)</td><td>Same shift.</td></tr><tr><td>17</td><td><code>rotationOldCommitment</code></td><td><code>rotationNewWallet</code></td><td>(V5.1 slot 18 → V5.2 slot 17)</td></tr><tr><td>18</td><td><code>rotationNewWallet</code></td><td><code>bindingPkXHi</code></td><td><strong>NEW</strong>: upper 128 bits of <code>parser.pkBytes[1..33]</code>, big-endian.</td></tr><tr><td>19</td><td>—</td><td><code>bindingPkXLo</code></td><td><strong>NEW</strong>: lower 128 bits of <code>parser.pkBytes[1..33]</code>.</td></tr><tr><td>20</td><td>—</td><td><code>bindingPkYHi</code></td><td><strong>NEW</strong>: upper 128 bits of <code>parser.pkBytes[33..65]</code>.</td></tr><tr><td>21</td><td>—</td><td><code>bindingPkYLo</code></td><td><strong>NEW</strong>: lower 128 bits of <code>parser.pkBytes[33..65]</code>.</td></tr></tbody></table><p>The 4 new limbs are each <code>Bits2Num(128)</code>-packed in-circuit (big-endian convention, matches the contract&#39;s <code>bytes16(uint128(...))</code> reconstruction). The contract reconstructs the 64-byte uncompressed pk (no SEC1 0x04 prefix) and runs <code>keccak256(...)[12:32]</code> to derive the address — full mirror of EVM&#39;s <code>address = keccak(pubkey)[12:]</code> derivation.</p><h3 id="custom-errors" tabindex="-1">Custom errors <a class="header-anchor" href="#custom-errors" aria-label="Permalink to &quot;Custom errors&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Error</th><th>V5.1</th><th>V5.2</th><th>Notes</th></tr></thead><tbody><tr><td><code>BadSender()</code> <code>0xf9b5d12d</code></td><td>✅ present</td><td>❌ <strong>removed</strong></td><td>Replaced by <code>WalletDerivationMismatch</code> (semantics generalize).</td></tr><tr><td><code>WalletDerivationMismatch()</code> <code>0x02373a16</code></td><td>—</td><td>✅ <strong>NEW</strong></td><td>Reverts when the keccak-derived address from <code>bindingPkX/Y</code> limbs ≠ <code>msg.sender</code>. Subsumes <code>BadSender</code>.</td></tr><tr><td><code>WrongRegisterModeNoOp()</code> <code>0xecd3e1cc</code></td><td>—</td><td>✅ <strong>NEW</strong></td><td>Reverts when register-mode <code>rotationNewWallet</code> (slot 17) ≠ <code>uint160(msg.sender)</code>. Replaces V5.1&#39;s in-circuit <code>ForceEqualIfEnabled</code> (<code>(1 - rotationMode) * (rotationNewWallet - msgSender) === 0</code>), which can no longer reference the now-absent in-circuit <code>msgSender</code>. The paired <code>rotationOldCommitment === identityCommitment</code> no-op stays in-circuit (no <code>msgSender</code> dependency).</td></tr><tr><td><code>BindingPkLimbOutOfRange()</code> <code>0x071478a6</code></td><td>—</td><td>✅ <strong>NEW</strong></td><td>Defense-in-depth revert when any of <code>bindingPkX/Y Hi/Lo</code> exceeds <code>2^128 - 1</code>. The circuit&#39;s <code>Bits2Num(128)</code> constraint should ensure this; the explicit revert surfaces a hypothetical circuit bug as a diagnosable error rather than silent <code>uint128</code> truncation.</td></tr></tbody></table><p>All other custom error selectors (<code>BadProof</code>, <code>BadSignedAttrsHi/Lo</code>, <code>BadLeafSpki</code>, <code>BadIntSpki</code>, <code>BadLeafSig</code>, <code>BadIntSig</code>, <code>BadTrustList</code>, <code>BadPolicy</code>, <code>StaleBinding</code>, <code>FutureBinding</code>, <code>AlreadyRegistered</code>, <code>WrongMode</code>, <code>CommitmentMismatch</code>, <code>WalletNotBound</code>, <code>CtxAlreadyUsed</code>, <code>UnknownIdentity</code>, <code>InvalidNewWallet</code>, <code>InvalidRotationAuth</code>, <code>OnlyAdmin</code>, <code>ZeroAddress</code>, <code>PoseidonDeployFailed</code>, <code>PoseidonStaticcallFailed</code>, <code>PrecompileCallFailed</code>, <code>SpkiLength</code>, <code>SpkiPrefix</code>) are byte-identical V5.1 → V5.2.</p><h2 id="storage-layout" tabindex="-1">Storage layout <a class="header-anchor" href="#storage-layout" aria-label="Permalink to &quot;Storage layout&quot;">​</a></h2><p>Verified via <code>forge inspect QKBRegistryV5_2 storageLayout</code> and diffed against V5.1 — <strong>identical</strong>, all 7 slots match by name, type, slot index, offset, and size:</p><table tabindex="0"><thead><tr><th>Slot</th><th>Name</th><th>Type</th><th>V5.1</th><th>V5.2</th></tr></thead><tbody><tr><td>0</td><td><code>admin</code></td><td><code>address</code></td><td>✓</td><td>✓</td></tr><tr><td>1</td><td><code>trustedListRoot</code></td><td><code>bytes32</code></td><td>✓</td><td>✓</td></tr><tr><td>2</td><td><code>policyRoot</code></td><td><code>bytes32</code></td><td>✓</td><td>✓</td></tr><tr><td>3</td><td><code>nullifierOf</code></td><td><code>mapping(address =&gt; bytes32)</code></td><td>✓</td><td>✓</td></tr><tr><td>4</td><td><code>identityCommitments</code></td><td><code>mapping(bytes32 =&gt; bytes32)</code></td><td>✓</td><td>✓</td></tr><tr><td>5</td><td><code>identityWallets</code></td><td><code>mapping(bytes32 =&gt; address)</code></td><td>✓</td><td>✓</td></tr><tr><td>6</td><td><code>usedCtx</code></td><td><code>mapping(bytes32 =&gt; mapping(bytes32 =&gt; bool))</code></td><td>✓</td><td>✓</td></tr></tbody></table><p><strong>Note:</strong> the registry is non-upgradeable. Storage-layout parity is documented for off-chain indexers / <code>eth_getStorageAt</code> consumers — there is no in-place upgrade path. V5.1 → V5.2 transition is a fresh deploy + holder re-registration via the existing fresh-QES flow.</p><h2 id="constructor-signature" tabindex="-1">Constructor signature <a class="header-anchor" href="#constructor-signature" aria-label="Permalink to &quot;Constructor signature&quot;">​</a></h2><p>Byte-identical V5.1 → V5.2:</p><div class="language-solidity vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">solidity</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">constructor</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    IGroth16VerifierV5_2</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> _verifier,    </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// ← was IGroth16VerifierV5_1; same shape</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    address</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> _admin,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    bytes32</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> _initialTrustedListRoot,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    bytes32</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> _initialPolicyRoot</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><p>Side effects also unchanged:</p><ul><li>CREATE-deploy <code>PoseidonT3</code> (~9.8 KB) and <code>PoseidonT7</code> (~23.6 KB); cache as immutables for cheap reads.</li><li>Set <code>admin</code> + initial <code>trustedListRoot</code> + initial <code>policyRoot</code>.</li><li>Revert <code>ZeroAddress()</code> on zero verifier or zero admin.</li></ul><p><code>DeployV5_2.s.sol</code> (<code>packages/contracts/script/DeployV5_2.s.sol</code>, commit <code>9df1bfc</code>) mirrors <code>DeployV5.s.sol</code> (V5/V5.1) verbatim except for the imports (verifier + registry types). Same env layout (<code>PRIVATE_KEY</code>, <code>ADMIN_ADDRESS</code>, <code>INITIAL_TRUST_ROOT</code>, <code>INITIAL_POLICY_ROOT</code>, <code>MINT_DEADLINE</code>, optional <code>GROTH16_VERIFIER_ADDR</code>, optional <code>CHAIN_LABEL</code>), same broadcast flow, same dev-fallback <code>Groth16VerifierV5_2Placeholder</code> when <code>GROTH16_VERIFIER_ADDR</code> is unset.</p><h2 id="gas-measurements" tabindex="-1">Gas measurements <a class="header-anchor" href="#gas-measurements" aria-label="Permalink to &quot;Gas measurements&quot;">​</a></h2><p>Real-tuple snapshot via the V5.2 single-contributor stub-ceremony Groth16 verifier (<code>Groth16VerifierV5_2Stub.sol</code>), measured by <code>RealTupleGasSnapshotV5_2.t.sol</code>. Comparison against V5.1&#39;s <code>RealTupleGasSnapshotTest</code> (commit <code>04b4a71</code>):</p><table tabindex="0"><thead><tr><th>Path</th><th>V5.1 (real tuple)</th><th>V5.2 (real tuple)</th><th>Δ</th></tr></thead><tbody><tr><td><code>test_real_tuple_full_register_gas</code></td><td>2,169,461</td><td><strong>2,198,170</strong></td><td>+28,709 (+1.32%)</td></tr><tr><td><code>test_real_tuple_groth16_verify_only_gas</code></td><td>378,344</td><td>405,248</td><td>+26,904 (+7.11%)</td></tr><tr><td><code>test_register_gas_bisection_by_gate</code> (sum)</td><td>1,594,344</td><td>1,603,399</td><td>+9,055 (+0.57%)</td></tr></tbody></table><p>V5.2 NEW per-gate cost (from bisection):</p><table tabindex="0"><thead><tr><th>Gate</th><th>Cost</th></tr></thead><tbody><tr><td>Gate 2a-prime (keccak-derive holder addr from bindingPkX/Y limbs)</td><td><strong>9,047 gas</strong></td></tr></tbody></table><p>Decomposition of the +28,709 register delta:</p><ul><li><strong>+9,047 gas</strong> — Gate 2a-prime keccak-derive (the core V5.2 amendment cost)</li><li><strong>+26,904 gas</strong> — Groth16 verify (22-input vs 19-input pairing equation: 3 extra IC scalar muls + 3 extra G1 adds)</li><li><strong>−7,242 gas</strong> — net offset (smaller calldata from msgSender drop; register-mode no-op gate is now a single SLOAD-free inequality instead of an in-circuit <code>ForceEqualIfEnabled</code> constraint)</li></ul><p><strong>Spec ceiling 2.5M (V5 §3, revised at commit <code>def6270</code>) holds</strong> — V5.2 register at 2.20M leaves <strong>~14% regression headroom</strong> (vs V5.1&#39;s ~16%).</p><p><code>rotateWallet()</code> not measured here (<code>RealTupleGasSnapshotV5_2</code> covers register only). V5.2 <code>rotateWallet</code> is functionally equivalent to V5.1 — the rotation flow doesn&#39;t traverse the keccak-derive gate. Projected real-pairing rotateWallet ≈ V5.1&#39;s ~380K-400K range.</p><h2 id="constraint-count-ceremony-pot-size" tabindex="-1">Constraint count + ceremony pot size <a class="header-anchor" href="#constraint-count-ceremony-pot-size" aria-label="Permalink to &quot;Constraint count + ceremony pot size&quot;">​</a></h2><table tabindex="0"><thead><tr><th></th><th>V5.1</th><th>V5.2</th></tr></thead><tbody><tr><td>Constraint count</td><td>4,022,171</td><td><strong>3,876,304</strong> (−145,867)</td></tr><tr><td>Powers-of-tau</td><td>pot23 (8,388,608)</td><td><strong>pot22 (4,194,304)</strong></td></tr><tr><td>Headroom</td><td>~52%</td><td><strong>~7.6%</strong></td></tr></tbody></table><p>V5.2&#39;s −145,867 constraint reduction comes entirely from removing V5.1 §6.8&#39;s <code>Secp256k1AddressDerive</code> keccak template (the in-circuit keccak gate that proved <code>address = keccak(pkBytes)[12:32]</code>). The contract picks up this responsibility at Gate 2a-prime, paying ~9K gas per call instead of ~145K constraints per proof.</p><h2 id="what-stayed-the-same" tabindex="-1">What stayed the same <a class="header-anchor" href="#what-stayed-the-same" aria-label="Permalink to &quot;What stayed the same&quot;">​</a></h2><ul><li><strong><code>IQKBRegistry</code> interface</strong> — V5.2 implements it; selectors and return types byte-identical to V5/V5.1. Third-party contracts that depend only on this read interface (e.g., <code>IdentityEscrowNFT.isVerified()</code>, external SDK readers) work unchanged.</li><li><strong>Storage layout</strong> — all 7 slots byte-identical V5.1 → V5.2.</li><li><strong>Constructor signature</strong> — <code>(verifier, admin, trustRoot, policyRoot)</code> parity-equivalent.</li><li><strong>Poseidon deployment pattern</strong> — CREATE-deploy T3 + T7 in constructor; cached as immutables.</li><li><strong>rotateWallet auth pattern</strong> — ECDSA sig from oldWallet&#39;s privkey over the rotation payload; bindingPk limbs in the proof are not consulted at rotation gate time.</li><li><strong>Per-(identity, ctx) anti-Sybil</strong> — <code>usedCtx[fp][ctxKey]</code> bookkeeping unchanged.</li><li><strong>First-claim nullifier semantics</strong> — V5.1 invariant 4 (<code>nullifierOf</code> is write-once on first-claim, migrates atomically on <code>rotateWallet</code>) preserved verbatim.</li><li><strong>Real-Diia E2E suite</strong> — <code>RealDiiaE2ETest</code> (V4 baseline) unaffected; V5.2 is independent of V4.</li></ul><h2 id="migration-guidance" tabindex="-1">Migration guidance <a class="header-anchor" href="#migration-guidance" aria-label="Permalink to &quot;Migration guidance&quot;">​</a></h2><h3 id="for-sdk-consumers-web-integrators" tabindex="-1">For SDK consumers (web, integrators) <a class="header-anchor" href="#for-sdk-consumers-web-integrators" aria-label="Permalink to &quot;For SDK consumers (web, integrators)&quot;">​</a></h3><ol><li>Bump dependency: <code>@qkb/sdk@0.5.2-pre</code>.</li><li><strong>If you only read</strong> (<code>isVerified</code>, <code>nullifierOf</code>, <code>trustedListRoot</code>): no changes. Existing <code>qkbRegistryV5_1Abi</code> calls work against the V5.2 deployment, but prefer <code>qkbRegistryV5_2Abi</code> for forward compatibility.</li><li><strong>If you write</strong> (<code>register</code>, <code>rotateWallet</code>): switch to <code>qkbRegistryV5_2Abi</code>. The 22-field public-signal struct is generated by the new witness builder (web-eng A7.3); follow the V5.2 web flow.</li><li><strong>If you classify reverts</strong>: add the 3 new V5.2 selectors to your error decoder: <ul><li><code>WalletDerivationMismatch()</code> <code>0x02373a16</code></li><li><code>WrongRegisterModeNoOp()</code> <code>0xecd3e1cc</code></li><li><code>BindingPkLimbOutOfRange()</code> <code>0x071478a6</code> Drop V5.1&#39;s <code>BadSender()</code> <code>0xf9b5d12d</code> (no longer emitted).</li></ul></li></ol><h3 id="for-deployer-tooling" tabindex="-1">For deployer-tooling <a class="header-anchor" href="#for-deployer-tooling" aria-label="Permalink to &quot;For deployer-tooling&quot;">​</a></h3><ol><li>Use <code>script/DeployV5_2.s.sol</code> instead of <code>script/DeployV5.s.sol</code>.</li><li>Same env vars; same broadcast invocation pattern; same <code>GROTH16_VERIFIER_ADDR</code>-or-placeholder fallback.</li><li>Production deploys MUST pass <code>GROTH16_VERIFIER_ADDR</code> pointing at the real ceremonied V5.2 verifier (post-Phase-B multi-contributor ceremony). The script logs a loud warning when the placeholder is wired in.</li></ol><h3 id="for-holders" tabindex="-1">For holders <a class="header-anchor" href="#for-holders" aria-label="Permalink to &quot;For holders&quot;">​</a></h3><p>V5.1 → V5.2 is a <strong>fresh deploy</strong>, not an upgrade. Existing V5.1 holders re-register against the new V5.2 registry via the standard fresh-QES flow. The two registries can coexist on-chain during the transition window; downstream consumers point at one or the other via deployment-fixture configuration (<code>fixtures/contracts/{sepolia,mainnet}.json</code>).</p><h2 id="acceptance" tabindex="-1">Acceptance <a class="header-anchor" href="#acceptance" aria-label="Permalink to &quot;Acceptance&quot;">​</a></h2><ul><li><code>forge build</code>: clean (<code>via_ir</code>, <code>optimizer_runs=200</code>).</li><li><code>forge test</code>: <strong>410 passed / 0 failed / 1 skipped / 411 total</strong> (1 skipped = <code>test_deploy_base_sepolia_fork</code>, env-gated). +30 V5.2 unit tests (<code>QKBRegistryV5_2.t.sol</code>) + 4 V5.2 real-tuple integration tests (<code>RealTupleGasSnapshotV5_2.t.sol</code>) over V5.1 baseline.</li><li><code>forge snapshot</code>: refreshed at <code>packages/contracts/snapshots/gas-snapshot.txt</code> (commit <code>0118a93</code>).</li><li><code>pnpm -F @qkb/sdk test</code>: 179/179 pass (T3 ABI surface check, commit <code>baed9d7</code>).</li><li>Cross-package integrity: <code>Groth16VerifierV5_2Stub.sol</code> sha256 matches <code>ceremony/v5_2/zkey.sha256</code> per circuits-eng&#39;s pump (lead-verified at pump time).</li></ul><h2 id="outstanding-before-mainnet" tabindex="-1">Outstanding before mainnet <a class="header-anchor" href="#outstanding-before-mainnet" aria-label="Permalink to &quot;Outstanding before mainnet&quot;">​</a></h2><ul><li><strong>V5.2 multi-contributor Phase-B ceremony</strong> (circuits-eng §11 equivalent for V5.2) — produces the real production verifier, replacing the single-contributor stub.</li><li><strong>Sepolia E2E gate</strong> (orchestration §9.4) — full register flow against real V5.2 ceremonied verifier on Base Sepolia.</li><li><strong>web-eng A7.3 completion</strong> — V5.2 witness builder + register calldata encoder.</li></ul><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ul><li>V5 architecture spec: <code>docs/superpowers/specs/2026-04-29-v5-architecture-design.md</code></li><li>V5.1 wallet-bound amendment: <code>docs/superpowers/specs/2026-04-30-wallet-bound-nullifier-amendment.md</code></li><li><strong>V5.2 keccak-on-chain amendment design (v0.4, locked at <code>8f5277f</code>):</strong> <code>docs/superpowers/specs/2026-05-01-keccak-on-chain-amendment.md</code></li><li><strong>V5.2 contract-side review (PASS-WITH-NOTES):</strong> <code>docs/superpowers/specs/2026-05-01-keccak-on-chain-contract-review.md</code></li><li>V5 architecture orchestration: <code>docs/superpowers/plans/2026-04-29-v5-architecture-orchestration.md</code></li><li>Gas-acceptance revision (600K → 2.5M): commit <code>def6270</code></li></ul>`,58)])])}const u=t(a,[["render",s]]);export{p as __pageData,u as default};
